#nullable enable // autogenerated

using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Entities
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.destroyOutsideWater)]
    public class DestroyOutsideWaterBehaviour : EntityBehaviourDefinition
    {
        public DestroyOutsideWaterBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Update(Entity entity)
        {
            base.Update(entity);
            if (entity.IsOnGround && !entity.IsOnWater())
            {
                entity.Die();
            }
        }
    }

}
